const body = $input.first().json.body || $input.first().json;
const userId = body.user_id;
const orderId = body.order_id;
const eventType = body.event_type;
if (eventType !== 'order.new') return [{ json: { _skip: true, reason: `event ${eventType} diabaikan (hanya order.new)` } }];
if (!userId || !orderId) throw new Error('Webhook payload missing user_id or order_id');
const APP_ID = 'NEW_APP_ID';
const APP_SECRET = 'NEW_APP_SECRET';
const ts = Math.floor(Date.now() / 1000);
const hmacMessage = `${APP_ID}:${ts}:${APP_SECRET}`;
return [{ json: { app_id: APP_ID, api_secret: APP_SECRET, user_id: userId, order_id: orderId, event_type: eventType, ts, hmacMessage, target_url: `https://api.berdu.id/v0.0/order/detail?user_id=${userId}&order_id=${orderId}` } }];

const d = $input.first().json;
const authHeader = `${d.app_id}.${d.ts}.${d.signature}`;
return [{ json: { ...d, authHeader } }];

const d = $input.first().json;
const order = d.body || d;
function normalizePhone(raw) { if (!raw) return null; return raw.toString().replace(/\s+/g,'').replace(/^\+/,'').replace(/^0/,'62').replace(/^8/,'628'); }
function formatRupiah(num) { return 'Rp' + Number(num).toLocaleString('id-ID'); }
const addr = order.shipping_address || {};
const phone = normalizePhone(addr.phone);
const customerName = addr.firstName || 'Pelanggan';
const assignedStaff = order.assigned_to_staff;
const shippingCost = order.shipping_cost || 0;
const total = order.total || 0;
const productsSubtotal = (order.products || []).reduce((sum, p) => sum + (p.price * p.count), 0);
const productsList = (order.products || []).map(p => `${p.name} (${p.count}x)`).join(', ');
const shippingAddress = addr.address || '';
const shippingDistrict = addr.district || '';
const shippingCity = addr.city || '';
const staffMap = { 'B-1apQSy': { platform: 'kirimdev', phoneId: 'AISYAH_PHONE_ID', senderName: 'Aisyah', templateName: 'whatsapp_notif_order_aisyah' }, 'B-1CxSmL': { platform: 'kirimdev', phoneId: 'RISMA_PHONE_ID', senderName: 'Risma', templateName: 'whatsapp_notif_order_risma_v2' }, 'B-Z28TdYc': { platform: 'kirimdev', phoneId: 'AZELIA_PHONE_ID', senderName: 'Azelia', templateName: 'whatsapp_notif_order_azela' }, 'B-NCIXt': { platform: 'kirimdev', phoneId: 'LILA_PHONE_ID', senderName: 'Lila', templateName: 'whatsapp_notif_order_lila' } };
const csConfig = staffMap[assignedStaff];
if (!csConfig) return [{ json: { _skip: true, reason: `staff ${assignedStaff} tidak ada di mapping` } }];
if (csConfig.phoneId === 'PENDING' || csConfig.templateName === 'PENDING') return [{ json: { _skip: true, reason: `${csConfig.senderName} belum ready (PHONE_ID/template pending)` } }];
if (!phone) return [{ json: { _skip: true, reason: 'phone tidak ditemukan di order' } }];
const webhookData = $('Extract Webhook Data').first().json;
const templateParams = [ customerName, csConfig.senderName, productsList, formatRupiah(productsSubtotal), formatRupiah(shippingCost), formatRupiah(total), phone, shippingAddress, shippingDistrict, shippingCity, (order.url || '') ];
const kirimDevBody = { messaging_product: 'whatsapp', to: '+' + phone, type: 'template', template: { name: csConfig.templateName, language: { code: 'id' }, components: [{ type: 'body', parameters: templateParams.map(text => ({ type: 'text', text: String(text).replace(/\s+/g, ' ').trim() })) }] } };
try { await this.helpers.httpRequest({ method: 'POST', url: 'https://n8n.miqra.dev/webhook/conversation-state', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ action: 'set_order', phone, csName: csConfig.senderName, productName: (order.products || [])[0]?.name || '', products: productsList, productsSubtotal: formatRupiah(productsSubtotal), shippingCost: formatRupiah(shippingCost), total: formatRupiah(total), customerName, shippingAddress, shippingDistrict, shippingCity, order_id: webhookData.order_id }) }); } catch (_) {} return [{ json: { phone, customerName, assignedStaff, csConfig, total: formatRupiah(total), productsSubtotal: formatRupiah(productsSubtotal), shippingCost: formatRupiah(shippingCost), products: productsList, shippingAddress, shippingDistrict, shippingCity, templateParams, event_type: webhookData.event_type, order_id: webhookData.order_id, kirimDevBody } }];

const r = $input.first().json;
const status = (r.data && r.data.status) || r.statusCode || (r._skip ? 'skipped' : 'unknown');
console.log('KirimDev v2 done:', JSON.stringify({ status, request_id: r.request_id || null, reason: r.reason || null }));
return [{ json: { logged: true, status, ts: new Date().toISOString() } }];
